12	// TestRecoverGitIndexLock_NoLock returns "not present" cleanly when the
13	// lock file does not exist.
14	func TestRecoverGitIndexLock_NoLock(t *testing.T) {
15		dir := t.TempDir()
16		if err := os.Mkdir(filepath.Join(dir, ".git"), 0o755); err != nil {
17			t.Fatalf("setup .git: %v", err)
18		}
19		result, err := recoverGitIndexLock(dir)
20		if err != nil {
21			t.Fatalf("recoverGitIndexLock: %v", err)
22		}
23		if result.Removed {
24			t.Fatalf("Removed=true for missing lock")
25		}
26		if !strings.Contains(result.Reason, "not present") {
27			t.Fatalf("Reason: %q", result.Reason)
28		}
