31	// TestRecoverGitIndexLock_StaleByAge removes an unowned lock once it is
32	// older than gitIndexLockStaleAge.
33	func TestRecoverGitIndexLock_StaleByAge(t *testing.T) {
34		prev := gitIndexLockStaleAge
35		gitIndexLockStaleAge = 50 * time.Millisecond
36		t.Cleanup(func() { gitIndexLockStaleAge = prev })
37	
38		dir := t.TempDir()
39		if err := os.Mkdir(filepath.Join(dir, ".git"), 0o755); err != nil {
40			t.Fatalf("setup .git: %v", err)
41		}
42		lockPath := filepath.Join(dir, ".git", "index.lock")
43		if err := os.WriteFile(lockPath, nil, 0o644); err != nil {
44			t.Fatalf("create lock: %v", err)
45		}
46		old := time.Now().Add(-1 * time.Second)
47		if err := os.Chtimes(lockPath, old, old); err != nil {
48			t.Fatalf("chtimes: %v", err)
49		}
50	
51		result, err := recoverGitIndexLock(dir)
52		if err != nil {
53			t.Fatalf("recoverGitIndexLock: %v", err)
54		}
55		if !result.Removed {
56			t.Fatalf("expected Removed=true, got reason=%q", result.Reason)
57		}
58		if _, err := os.Stat(lockPath); !os.IsNotExist(err) {
59			t.Fatalf("lock still exists after recovery: %v", err)
60		}
61	}
