92	// TestRecoverGitIndexLock_DeadOwner removes the lock when lsof identifies
93	// a pid that is not alive. This test requires lsof and is skipped if
94	// unavailable.
95	func TestRecoverGitIndexLock_DeadOwner(t *testing.T) {
96		if _, err := exec.LookPath("lsof"); err != nil {
97			t.Skip("lsof not available on PATH")
98		}
99	
100		dir := t.TempDir()
101		if err := os.Mkdir(filepath.Join(dir, ".git"), 0o755); err != nil {
102			t.Fatalf("setup .git: %v", err)
103		}
104		lockPath := filepath.Join(dir, ".git", "index.lock")
105	
106		// Spawn a short-lived process that opens the lock file, then exits.
107		// While it is alive its pid owns the file; after exit, the file is
108		// unowned and lsof returns nothing.
109		cmd := exec.Command("sh", "-c", "exec 9>>"+lockPath+"; sleep 0.05")
110		if err := cmd.Start(); err != nil {
111			t.Fatalf("start helper: %v", err)
112		}
113		if err := cmd.Wait(); err != nil {
114			t.Fatalf("helper exited with error: %v", err)
115		}
116		// Helper is dead; lsof now returns nothing. Age the lock past stale
117		// threshold so the unowned-stale branch removes it.
118		prev := gitIndexLockStaleAge
119		gitIndexLockStaleAge = 1 * time.Millisecond
120		t.Cleanup(func() { gitIndexLockStaleAge = prev })
121	
122		time.Sleep(5 * time.Millisecond)
123		result, err := recoverGitIndexLock(dir)
124		if err != nil {
125			t.Fatalf("recoverGitIndexLock: %v", err)
126		}
127		if !result.Removed {
128			t.Fatalf("expected removal, reason=%q owner=%d alive=%v",
129				result.Reason, result.OwnerPID, result.OwnerAlive)
130		}
131	}
