134		cases := []struct {
135			name string
136			s    string
137			want bool
138		}{
139			{"fatal_file_exists", "fatal: Unable to create '/repo/.git/index.lock': File exists.", true},
140			{"combined_git_message", "fatal: Unable to create '/repo/.git/index.lock': File exists.\n\nAnother git process seems to be running in this repository", true},
141			{"unrelated", "fatal: not a git repository", false},
142			{"empty", "", false},
143		}
144		for _, tc := range cases {
145			t.Run(tc.name, func(t *testing.T) {
146				if got := isGitIndexLockError(tc.s); got != tc.want {
