2	
3	import (
4		"fmt"
5		"os"
6		"path/filepath"
7		"strconv"
8		"strings"
9		"time"
10	)
11	
12	// StaleLockAge is the duration after which a lock is considered stale
13	// and can be forcibly broken. Default: 2 hours.
14	var StaleLockAge = 2 * time.Hour
15	
16	// LockSample carries timing metrics for one Store.WithLock acquire/release cycle.
17	type LockSample struct {
18		LockDir string
19		Wait    time.Duration // time from WithLock entry to lock acquisition
20		Hold    time.Duration // time the callback held the lock
21	}
22	
23	// LockMetricsSink is called after each successful Store.WithLock acquire+release
24	// cycle. The zero value (nil) is a no-op. Tests may swap this to capture metrics.
25	var LockMetricsSink func(LockSample)
26	
27	// WithLock acquires the file lock, runs fn, then releases the lock.
28	// For external backends, locking is delegated to the backend tool.
29	func (s *Store) WithLock(fn func() error) error {
30		if s.backend != nil {
31			return s.backend.WithLock(fn)
32		}
33		waitStart := time.Now()
34		if err := s.acquireLock(); err != nil {
35			return err
36		}
37		waitDur := time.Since(waitStart)
38		holdStart := time.Now()
39		defer s.releaseLock()
40		fnErr := fn()
41		if sink := LockMetricsSink; sink != nil {
42			sink(LockSample{LockDir: s.LockDir, Wait: waitDur, Hold: time.Since(holdStart)})
43		}
44		return fnErr
45	}
46	
47	func (s *Store) acquireLock() error {
48		return acquireDirLock(s.Dir, s.LockDir, s.LockWait)
49	}
50	
51	// acquireDirLock is the file-lock primitive used by both Store and the
52	// standalone JSONLBackend. dir is the directory to ensure exists before the
53	// lock is taken; lockDir is the lock directory itself; wait bounds the spin.
54	func acquireDirLock(dir, lockDir string, wait time.Duration) error {
55		if err := os.MkdirAll(dir, 0o755); err != nil {
56			return fmt.Errorf("bead: lock dir: %w", err)
57		}
58	
59		deadline := time.Now().Add(wait)
60		for {
61			err := os.Mkdir(lockDir, 0o755)
62			if err == nil {
63				_ = os.WriteFile(filepath.Join(lockDir, "pid"),
64					[]byte(fmt.Sprintf("%d", os.Getpid())), 0o644)
65				_ = os.WriteFile(filepath.Join(lockDir, "acquired_at"),
66					[]byte(time.Now().UTC().Format(time.RFC3339)), 0o644)
67				return nil
68			}
69	
70			if breakStaleLockDir(lockDir) {
71				continue
72			}
73	
74			if time.Now().After(deadline) {
75				owner := "unknown"
76				pidData, _ := os.ReadFile(filepath.Join(lockDir, "pid"))
77				if len(pidData) > 0 {
78					owner = strings.TrimSpace(string(pidData))
79				}
80				return fmt.Errorf("bead: lock timeout (owner pid: %s)", owner)
81			}
82			time.Sleep(50 * time.Millisecond)
83		}
84	}
85	
86	// breakStaleLockDir checks if the existing lock is stale (owner dead or too
87	// old) and breaks it if so. Returns true if lock was broken.
88	func breakStaleLockDir(lockDir string) bool {
89		pidData, err := os.ReadFile(filepath.Join(lockDir, "pid"))
90		if err == nil {
91			pid, err := strconv.Atoi(strings.TrimSpace(string(pidData)))
92			if err == nil && pid > 0 && pid != os.Getpid() {
93				if !processAlive(pid) {
94					os.RemoveAll(lockDir)
95					return true
96				}
97			}
98		}
99	
100		acquiredData, err := os.ReadFile(filepath.Join(lockDir, "acquired_at"))
101		if err == nil {
102			acquired, err := time.Parse(time.RFC3339, strings.TrimSpace(string(acquiredData)))
103			if err == nil && time.Since(acquired) > StaleLockAge {
104				os.RemoveAll(lockDir)
105				return true
106			}
107		}
108	
109		return false
110	}
111	
112	func (s *Store) releaseLock() {
113		os.RemoveAll(s.LockDir)
114	}
