78	// Apply mutates one bead snapshot in place and persists the updated corpus.
79	// JSONLBackend keeps the generic load-mutate-save path here so higher-level
80	// callers can opt into the OperationApplier fast path without having to know
81	// the backend-specific write shape yet.
82	func (j *JSONLBackend) Apply(ctx context.Context, id string, op Operation) error {
83		if j == nil {
84			return fmt.Errorf("bead: nil jsonl backend")
85		}
86		if op == nil {
87			return fmt.Errorf("bead: nil operation")
88		}
89		if ctx != nil {
90			select {
91			case <-ctx.Done():
92				return ctx.Err()
93			default:
94			}
95		}
96		return j.WithLock(func() error {
97			beads, err := j.ReadAll()
98			if err != nil {
99				return err
100			}
101			found := false
102			now := time.Now().UTC()
103			for i := range beads {
104				if beads[i].ID != id {
105					continue
106				}
107				origID := beads[i].ID
108				origCreatedAt := beads[i].CreatedAt
109				if err := op.Apply(&beads[i]); err != nil {
110					return err
111				}
112				if beads[i].ID != origID || !beads[i].CreatedAt.Equal(origCreatedAt) {
113					return fmt.Errorf("bead: operation may not mutate immutable fields")
114				}
115				beads[i].UpdatedAt = now
116				found = true
117				break
118			}
119			if !found {
120				return fmt.Errorf("%w: %s", ErrNotFound, id)
121			}
122			return j.WriteAll(beads)
123		})
124	}
