126	func (j *JSONLBackend) WithLock(fn func() error) error {
127		wait := j.LockWait
128		if wait <= 0 {
129			wait = 10 * time.Second
130		}
131		if err := acquireDirLock(j.Dir, j.LockDir, wait); err != nil {
132			return err
133		}
134		defer os.RemoveAll(j.LockDir)
135		return fn()
136	}
