33	func TestRecoverGitIndexLock_StaleByAge(t *testing.T) {
34		prev := gitIndexLockStaleAge
35		gitIndexLockStaleAge = 50 * time.Millisecond
36		t.Cleanup(func() { gitIndexLockStaleAge = prev })
37	
38		dir := t.TempDir()
